mapper.select:
SELECT sr.id AS id, sr.substitute_date AS substituteDate, sr.lesson_id AS lessonId, sr.lesson_name AS lessonName, grade.id AS gradeId, grade.grade_group_name AS gradeName, sr.class_id AS classId, cla.class_name AS className, sr.subject_id AS subjectId, sub.subject_name AS subjectName, sr.original_teacher_id AS originalTeacherId, originalusr.username AS originalTeacherName, sr.substitute_teacher_id AS substituteTeacherId, substituteusr.username AS substituteTeacherName, sr.remark AS remark FROM substitute_record sr LEFT JOIN sys_user_school_rel originalusr ON originalusr.id = sr.original_teacher_id AND originalusr.school_id = #{schoolId} LEFT JOIN sys_user_school_rel substituteusr ON substituteusr.id = sr.substitute_teacher_id AND substituteusr.school_id = #{schoolId} LEFT JOIN subject_rel srl ON srl.id = sr.subject_id LEFT JOIN subject sub ON sub.id = srl.subject_id LEFT JOIN sys_class cla ON cla.id = sr.class_id LEFT JOIN grade_group grade ON grade.id = cla.grade_group WHERE sr.deleted = 0 AND sr.school_id = #{schoolId}
AND cla.id = #{reqModel.classId}
AND sr.subject_id = #{reqModel.subjectId}
AND sr.substitute_teacher_id = #{reqModel.teacherId}
AND substituteusr.username LIKE CONCAT('%', #{reqModel.teacherName}, '%')
AND sr.substitute_date >= #{reqModel.startTime}
AND sr.substitute_date <= #{reqModel.endTime}
AND cla.sid = #{reqModel.schoolYear}
ORDER BY sr.id DESC
